 struct node{
  char data;
  node*next;

 };

 class stack{
  private:
  node *topnode;

  public:
  stack(){
  topnode=NULL;
  }

  void push(char c){
  node*newnode=new node();
  newnode->data=c;
  newnode->next=topnode;
  topnode=newnode;
  }
  char pop(){
  if(topnode==NULL)return'\0';
  char c =topnode->data;
  node* temp=topnode;
  topnode=topnode->next;
  delete temp;
  return c;
  }
  bool isempty(){
  return topnode==NULL;
  }
 };
  bool palindrome(string s){
  stack st;
  for(char c:s){
  st.push(c);
  }
  for(char c:s){
  if(c!=st.pop())return false;
  }
  return true;
  }

