#include <iostream>
 #include <stack>
 #include <string>
 using namespace std;

 int evaluatePostfix(string expression) {
  stack<int> st;

  for (char c : expression) {
  if (isdigit(c)) {
  // If it's a digit, push it to stack
  st.push(c - '0');
  } else {
  // It's an operator
  if (c == '#') {
  // Unary operator: A# = A + 1
  int a = st.top();
  st.pop();
  st.push(a + 1);
  } else if (c == '$') {
  // Unary operator: A$ = A - 1
  int a = st.top();
  st.pop();
  st.push(a - 1);
  } else {
  // Binary operators: +, -, *, /
  int b = st.top(); st.pop();
  int a = st.top(); st.pop();

  switch (c) {
  case '+':
  st.push(a + b);
  break;
  case '-':
  st.push(a - b);
  break;
  case '*':
  st.push(a * b);
  break;
  case '/':
  if (b == 0) {
  // Division by zero: increase divisor by 2
  st.push(a / (b + 2));
  } else {
  st.push(a / b);
  }
  break;
  }
  }
  }
  }

  return st.top();
 }

 int main() {
  string expression;
  cin >> expression;

  cout << evaluatePostfix(expression) << endl;

  return 0;
 }

