 class Node{
  int x;
  int y;
  Node(int x, int y){
  this.x = x;
  this.y = y;
  }
 }
 public class Solution{
  public static void main(String args[]){
  Scanner sc = new Scanner(System.in);
  int N,M;
  N = sc.nextInt();
  M = sc.nextInt();
  int mat[][] = new int[N][M];
  for(int i=0;i<N;i++){
  for(int j=0;j<M;j++){
  mat[i][j] = sc.nextInt();
  }
  }
  int stx = sc.nextInt();
  int sty = sc.nextInt();
  int enx = sc.nextInt();
  int eny = sc.nextInt();
  int px= stx; 
  int py = sty;
  int cost = 0;
  cost += mat[stx][sty];
  ArrayList<Node>Path = new ArrayList<>();
  while(px!=enx && py!=eny){
  ArrayList<Node>pq = new ArrayList<>();
  int l1 = px;
  int l2 = py - 1;
  if(l2>= 0){
  pq.add(new Node(l1,l2)); 
  }
  int r1 = px;
  int r2 = py+1;
  if(r2 < M){
  pq.add(new Node(r1,r2));
  }
  int u1 = px - 1;
  int u2 = py;
  if(u1 >= 0){
  pq.add(new Node(u1,u2));
  }
  int d1 = px+1;
  int d2 = py;
  if(d1 <= N){
  pq.add(new Node(d1,d2));
  }
  Collections.sort(pq, (a,b)-> Integer.compare(mat[a.x][a.y], mat[b.x][b.y]));
  Node take = pq.get(0);
  cost += mat[take.x][ take.y];
  Path.add(new Node(take.x, take.y));
  px = take.x;
  py = take.y;
  }
  System.out.println("Minimum Cost: ");
  System.out.println(cost);
  System.out.println("Path: ");
  for(int i=0;i<Path.size();i++){

  System.out.print(Path.get(i).x+" ");
  System.out.print(Path.get(i).y);

  }
  System.out.println();


  }
 }

